#include <bits/stdc++.h>
using namespace std;
struct Node{
    int x,y,z;
}p[50004];
int n;
bool cmp(Node x,Node y){
    return x.z<y.z;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d",&p[i].x,&p[i].y,&p[i].z);
    sort(p+1,p+n+1,cmp);
    double ans=0;
    for(int i=2;i<=n;i++){
        ans+=sqrt(1.0*(p[i].x-p[i-1].x)*(p[i].x-p[i-1].x)+1.0*(p[i].y-p[i-1].y)*(p[i].y-p[i-1].y)+1.0*(p[i].z-p[i-1].z)*(p[i].z-p[i-1].z));
    }
    printf("%.3lf",ans);
    return 0;
}
